import{_ as d,c as n,a,b as r,d as s,r as o,o as i}from"./app-DxT-J_20.js";const h={};function p(c,t){const e=o("DateMeta");return i(),n("div",null,[t[0]||(t[0]=a("h1",{id:"무신사-스탠다드-musinsa-standard",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#무신사-스탠다드-musinsa-standard"},[a("span",null,"무신사 스탠다드 (Musinsa Standard)")])],-1)),r(e),t[1]||(t[1]=s('<p>무신사 스탠다드(Musinsa Standard)는 국내 최대 패션 이커머스 플랫폼 <strong>무신사</strong>(MUSINSA)의 자체 브랜드(PB, Private Brand)다. 2017년 론칭 이후 &quot;가성비 넘버원&quot; 포지셔닝으로 급성장했으며, 현재 무신사 플랫폼 내 단일 브랜드 기준 최상위 매출을 기록하는 브랜드다.</p><h2 id="무신사-musinsa-플랫폼-배경" tabindex="-1"><a class="header-anchor" href="#무신사-musinsa-플랫폼-배경"><span>무신사(MUSINSA) 플랫폼 배경</span></a></h2><p>무신사는 2003년 신발·스트리트패션 커뮤니티로 시작해 패션 커머스 플랫폼으로 성장했다. 현재 국내 패션 이커머스 1위로, 입점 브랜드 수 7,000개 이상, 월간 활성 이용자(MAU) 600만 명 이상 수준이다.</p><p>무신사 스탠다드는 이 플랫폼이 직접 기획·생산하는 PB 브랜드로, 플랫폼 데이터 기반으로 소비자 수요가 높은 아이템을 선별해 출시하는 방식으로 빠르게 성장했다.</p><h2 id="브랜드-포지셔닝" tabindex="-1"><a class="header-anchor" href="#브랜드-포지셔닝"><span>브랜드 포지셔닝</span></a></h2><p><strong>&quot;가장 기본적인 것을, 가장 잘 만든다&quot;</strong></p><p>무신사 스탠다드의 핵심은 <strong>베이직 아이템의 극한 가성비</strong>다. 유니클로, COS 등 글로벌 SPA 브랜드와 경쟁하는 포지션이지만, 국내 체형 데이터 기반 피팅과 더 낮은 가격이 강점이다.</p><table><thead><tr><th>비교</th><th>무신사 스탠다드</th><th>유니클로</th><th>COS</th></tr></thead><tbody><tr><td>가격대</td><td>1~5만원</td><td>2~5만원</td><td>5~15만원</td></tr><tr><td>기획 기반</td><td>국내 트렌드·체형 데이터</td><td>글로벌 표준</td><td>유럽 미니멀</td></tr><tr><td>품질</td><td>가격 대비 높음</td><td>안정적</td><td>프리미엄 소재</td></tr><tr><td>사이즈</td><td>S~4XL (넓은 인클루시브 사이징)</td><td>S~3XL</td><td>제한적</td></tr></tbody></table><h2 id="주요-인기-제품" tabindex="-1"><a class="header-anchor" href="#주요-인기-제품"><span>주요 인기 제품</span></a></h2><h3 id="크루넥-스웨트셔츠-후드-집업" tabindex="-1"><a class="header-anchor" href="#크루넥-스웨트셔츠-후드-집업"><span>크루넥 스웨트셔츠 / 후드 집업</span></a></h3><p>무신사 스탠다드를 대표하는 아이템. 두툼한 기모 안감, 적당한 오버핏, 다양한 컬러가 특징이다. 스타일링 사진이 풍부해 &quot;어떻게 입으면 되는지&quot; 명확하게 제시한다.</p><ul><li>소재: 코튼 혼방 기모</li><li>컬러: 블랙, 화이트, 그레이, 카키, 네이비 등 계절별 추가</li><li>가격: 2~3만원대</li><li>사이즈: S~4XL (빅사이즈 수요 대응)</li></ul><h3 id="슬랙스-와이드-팬츠" tabindex="-1"><a class="header-anchor" href="#슬랙스-와이드-팬츠"><span>슬랙스 / 와이드 팬츠</span></a></h3><p>테이퍼드·와이드 실루엣의 슬랙스 라인. 폴리에스터 혼방으로 구김이 적고 관리가 쉽다. 출근복과 캐주얼 두 용도로 모두 가능한 미드 포지션이다.</p><h3 id="트레이닝-팬츠-조거-팬츠" tabindex="-1"><a class="header-anchor" href="#트레이닝-팬츠-조거-팬츠"><span>트레이닝 팬츠 / 조거 팬츠</span></a></h3><p>일상·운동 겸용 트레이닝 라인. 가격 대비 소재감과 마감이 좋다는 평가를 받으며, 특히 &quot;집에서 입기 좋은 고급진 운동복&quot; 수요를 공략한다.</p><h3 id="에센셜-티셔츠" tabindex="-1"><a class="header-anchor" href="#에센셜-티셔츠"><span>에센셜 티셔츠</span></a></h3><p>기본 반팔 티. 두껍지 않고 가볍게 입을 수 있는 여름용. 오버핏·세미오버핏·슬림핏 라인 구분이 명확하다.</p><h3 id="패딩·아우터-시즌-한정" tabindex="-1"><a class="header-anchor" href="#패딩·아우터-시즌-한정"><span>패딩·아우터 (시즌 한정)</span></a></h3><p>시즌마다 출시하는 롱패딩, 숏패딩, 코트 등. 10~15만원대에 고급 패딩 브랜드의 외형을 구현하는 가성비로 매 시즌 조기 품절이 발생한다.</p><h2 id="무신사-스탠다드-블랙-musinsa-standard-black" tabindex="-1"><a class="header-anchor" href="#무신사-스탠다드-블랙-musinsa-standard-black"><span>무신사 스탠다드 블랙 (Musinsa Standard Black)</span></a></h2><p>2022년부터 기존 라인의 상위 라인업으로 <strong>무신사 스탠다드 블랙</strong>을 운영하고 있다. 더 고급 소재와 디테일을 사용하며, 가격대는 일반 라인보다 30~50% 높다.</p><table><thead><tr><th>라인</th><th>특징</th><th>가격대</th></tr></thead><tbody><tr><td>무신사 스탠다드</td><td>기본 가성비 라인</td><td>1~5만원</td></tr><tr><td>무신사 스탠다드 블랙</td><td>프리미엄 소재·디테일</td><td>3~15만원</td></tr></tbody></table><h2 id="오프라인-매장" tabindex="-1"><a class="header-anchor" href="#오프라인-매장"><span>오프라인 매장</span></a></h2><p>온라인에서 시작했지만 현재 전국에 오프라인 스토어를 운영 중이다.</p><table><thead><tr><th>위치</th><th>형태</th></tr></thead><tbody><tr><td>홍대 플래그십</td><td>무신사 스탠다드 단독 대형 매장</td></tr><tr><td>강남</td><td>무신사 스탠다드 매장</td></tr><tr><td>성수</td><td>팝업 형태로 수시 운영</td></tr><tr><td>부산 서면</td><td>지방 거점 매장</td></tr></tbody></table><p>오프라인에서 실제 소재·피팅을 확인하고 온라인으로 추가 구매하는 패턴이 많다.</p><h2 id="구매-팁" tabindex="-1"><a class="header-anchor" href="#구매-팁"><span>구매 팁</span></a></h2><ul><li><strong>사이즈</strong>: 모델 신장 정보 + 구매자 후기 사진이 풍부하므로 꼭 참고. 오버핏 제품은 본인 실측보다 한 사이즈 아래를 권장하는 경우도 있음</li><li><strong>멤버십 할인</strong>: 무신사 멤버십 구독 시 추가 할인 가능</li><li><strong>세일 기간</strong>: 무신사 대학(무신사 세일)·블랙프라이데이 등 연 2~3회 대규모 세일 기간에 추가 10~20% 할인</li><li><strong>교환/반품</strong>: 무신사 공식몰 기준 30일 이내 무료 반품 가능</li></ul>',29))])}const m=d(h,[["render",p]]),u=JSON.parse('{"path":"/brands/musinsa-standard.html","title":"무신사 스탠다드 (Musinsa Standard)","lang":"ko-KR","frontmatter":{"description":"무신사 스탠다드 (Musinsa Standard)","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"무신사 스탠다드 (Musinsa Standard)\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T15:28:45.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/brands/musinsa-standard.html"}],["meta",{"property":"og:title","content":"무신사 스탠다드 (Musinsa Standard)"}],["meta",{"property":"og:description","content":"무신사 스탠다드 (Musinsa Standard)"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T15:28:45.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T15:28:45.000Z"}]]},"git":{"createdTime":1781278125000,"updatedTime":1781278125000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":1,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"4acea436e218471c65ee4423a1fa6aa81bc35514","time":1781278125000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: add Wellness (치경부마모증, 바벨스쿼트), Brands (DESKER, 무신사스탠다드), Products (ThinkPad)","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"brands/musinsa-standard.md","autoDesc":true}');export{m as comp,u as data};
